	details{border-top:1px solid var(--line);margin-top:13px;padding-top:12px}summary{cursor:pointer;color:var(--theme-text);font-size:9px;font-weight:650}.detail-copy{margin:9px 0 11px;color:var(--muted);font-size:8px;line-height:1.5}.credential-form,.connection-form{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:12px}.credential-form button,.connection-form button{align-self:end;min-height:40px;height:auto;line-height:1.3}.credential-form button{grid-column:1/-1}.connection-form button{grid-column:1/-1}.stored-status{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:7px;margin-top:10px}.stored-status span{display:grid;grid-template-columns:auto 1fr;align-items:center;column-gap:6px;padding:9px;border-radius:8px;background:var(--theme-soft);color:var(--purple)}.stored-status b{font-size:8px;color:var(--theme-text)}.stored-status small{grid-column:2;font-size:7px;color:var(--muted);overflow:hidden;text-overflow:ellipsis}.inline-form{display:grid;grid-template-columns:1fr 1fr auto;gap:7px;margin-top:10px}.danger summary,.danger button{color:#ef4444}
