	@media(max-width:850px){.tenant-grid{grid-template-columns:1fr}.grid{grid-template-columns:1fr}.grid .wide{grid-column:auto}.intro{align-items:flex-start;gap:18px}.owner-security{align-items:flex-start;flex-direction:column}.owner-security form{width:100%}.owner-security label{flex:1}.inline-form{grid-template-columns:1fr}.owner-head>div>span{display:none}}
	@media(max-width:560px){.intro{flex-direction:column}.facts,.stored-status,.credential-form,.connection-form{grid-template-columns:1fr}.connection-form .wide,.credential-form button,.connection-form button{grid-column:auto}.checks,.actions{flex-direction:column}.owner-security form{width:100%;align-items:stretch;flex-direction:column}.owner-security label{min-width:0}}
